import { test } from 'node:test'
import assert from 'node:assert/strict'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

test('geo() extracts geolocation from Vercel headers', () => {
  const headers = new Headers({
    'x-vercel-ip-city': 'San Francisco',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'CA',
    'x-vercel-ip-latitude': '37.7749',
    'x-vercel-ip-longitude': '-122.4194',
    'x-vercel-ip-timezone': 'America/Los_Angeles',
  })

  const result = geo({ headers })

  assert.equal(result.city, 'San Francisco')
  assert.equal(result.countryCode, 'US')
  assert.equal(result.country, 'United States')
  assert.equal(result.region, 'CA')
  assert.equal(result.latitude, '37.7749')
  assert.equal(result.longitude, '-122.4194')
  assert.equal(result.timezone, 'America/Los_Angeles')
})

test('geoFromHeaders() falls back to Cloudflare cf-ipcountry header', () => {
  const headers = new Headers({
    'cf-ipcountry': 'GB',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'GB')
  assert.equal(result.country, 'United Kingdom')
  assert.equal(result.city, undefined)
  assert.equal(result.region, undefined)
})

test('geoFromHeaders() prefers x-vercel-ip-country over cf-ipcountry', () => {
  const headers = new Headers({
    'x-vercel-ip-country': 'DE',
    'cf-ipcountry': 'FR',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'DE')
  assert.equal(result.country, 'Germany')
})

test('geoFromHeaders() normalizes countryCode to uppercase', () => {
  const headers = new Headers({
    'x-vercel-ip-country': 'jp',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'JP')
  assert.equal(result.country, 'Japan')
})

test('geoFromHeaders() returns undefined fields when headers are missing', () => {
  const headers = new Headers()

  const result = geoFromHeaders(headers)

  assert.equal(result.city, undefined)
  assert.equal(result.country, undefined)
  assert.equal(result.countryCode, undefined)
  assert.equal(result.region, undefined)
  assert.equal(result.latitude, undefined)
  assert.equal(result.longitude, undefined)
  assert.equal(result.timezone, undefined)
})

test('geoFromHeaders() country is undefined for unknown countryCode', () => {
  const headers = new Headers({
    'x-vercel-ip-country': 'ZZ',
  })

  const result = geoFromHeaders(headers)

  assert.equal(result.countryCode, 'ZZ')
  assert.equal(result.country, undefined)
})

test('geoFromHeaders() looks up country names for all supported codes', () => {
  const cases: Array<[string, string]> = [
    ['US', 'United States'],
    ['GB', 'United Kingdom'],
    ['DE', 'Germany'],
    ['FR', 'France'],
    ['JP', 'Japan'],
    ['CN', 'China'],
    ['IN', 'India'],
    ['BR', 'Brazil'],
    ['AU', 'Australia'],
    ['CA', 'Canada'],
  ]

  for (const [code, name] of cases) {
    const headers = new Headers({ 'x-vercel-ip-country': code })
    const result = geoFromHeaders(headers)
    assert.equal(result.country, name, `Expected country name for ${code}`)
  }
})

test('isInRegion() returns true when countryCode matches', () => {
  const location = { countryCode: 'US', country: 'United States' }
  assert.equal(isInRegion(location, ['US', 'CA', 'MX']), true)
})

test('isInRegion() returns false when countryCode does not match', () => {
  const location = { countryCode: 'GB', country: 'United Kingdom' }
  assert.equal(isInRegion(location, ['US', 'CA', 'MX']), false)
})

test('isInRegion() is case-insensitive', () => {
  const location = { countryCode: 'us' }
  assert.equal(isInRegion(location, ['US']), true)
  assert.equal(isInRegion(location, ['us']), true)
})

test('isInRegion() returns false when countryCode is undefined', () => {
  const location = {}
  assert.equal(isInRegion(location, ['US']), false)
})

test('geoDistance() calculates Haversine distance between New York and London', () => {
  // New York: 40.7128 N, 74.0060 W
  // London:   51.5074 N, 0.1278 W
  // Expected: ~5570 km
  const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(distance - 5570) < 50,
    `Expected ~5570 km, got ${distance.toFixed(1)} km`
  )
})

test('geoDistance() returns 0 for identical coordinates', () => {
  const distance = geoDistance('51.5074', '-0.1278', '51.5074', '-0.1278')
  assert.equal(distance, 0)
})

test('geoDistance() is symmetric', () => {
  const d1 = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  const d2 = geoDistance('51.5074', '-0.1278', '40.7128', '-74.0060')
  assert.ok(
    Math.abs(d1 - d2) < 0.001,
    `Expected symmetric distances, got ${d1} and ${d2}`
  )
})

